import io.ktor.http.*
import io.ktor.server.application.*
import io.ktor.server.request.*
import io.ktor.server.response.*
import io.ktor.server.routing.*
import org.jetbrains.exposed.sql.*
import org.jetbrains.exposed.sql.transactions.transaction
import java.util.UUID

fun Route.postRoutes() {
    route("/posts") {
        get {
            val items = transaction { Posts.selectAll().map { it.toPost() } }
            call.respond(items)
        }

        get("/{id}") {
            val id = call.parameters["id"]?.runCatching { UUID.fromString(this) }?.getOrNull()
                ?: return@get call.respond(HttpStatusCode.BadRequest)
            val item = transaction {
                Posts.selectAll().where { Posts.id eq id }.singleOrNull()?.toPost()
            }
            if (item == null) call.respond(HttpStatusCode.NotFound)
            else call.respond(item)
        }

        post {
            val body = call.receive<CreatePost>()
            val item = transaction {
                Posts.insertReturning {
                    it[title] = body.title
                    it[body] = body.body
                    it[published] = body.published
                }.single().toPost()
            }
            call.respond(HttpStatusCode.Created, item)
        }

        put("/{id}") {
            val id = call.parameters["id"]?.runCatching { UUID.fromString(this) }?.getOrNull()
                ?: return@put call.respond(HttpStatusCode.BadRequest)
            val body = call.receive<UpdatePost>()
            val updated = transaction {
                val count = Posts.update({ Posts.id eq id }) {
                    body.title?.let { v -> it[title] = v }
                    body.body?.let { v -> it[body] = v }
                    body.published?.let { v -> it[published] = v }
                }
                if (count == 0) null
                else Posts.selectAll().where { Posts.id eq id }.single().toPost()
            }
            if (updated == null) call.respond(HttpStatusCode.NotFound)
            else call.respond(updated)
        }

        delete("/{id}") {
            val id = call.parameters["id"]?.runCatching { UUID.fromString(this) }?.getOrNull()
                ?: return@delete call.respond(HttpStatusCode.BadRequest)
            val deleted = transaction { Posts.deleteWhere { Posts.id eq id } }
            if (deleted == 0) call.respond(HttpStatusCode.NotFound)
            else call.respond(HttpStatusCode.NoContent)
        }
    }
}

